def first_missing_positive(xs):
    n = len(xs)
    for i in range(n):
        while 1 <= xs[i] <= n and xs[i] != xs[xs[i] - 1]:
            target = xs[i] - 1
            xs[i], xs[target] = xs[target], xs[i]
    for i in range(n):
        if xs[i] != i + 1:
            return i + 1
    return n + 1
